-- Resincronización de secuencias seriales tras INSERTs con IDs explícitos
SELECT setval(pg_get_serial_sequence('ciudadano', 'ciudadano_id'), (SELECT MAX(ciudadano_id) FROM ciudadano));
SELECT setval(pg_get_serial_sequence('funcionario', 'funcionario_id'), (SELECT MAX(funcionario_id) FROM funcionario));
